# Self-extracting patch script generated to apply workspace changes on server
import base64
import io
import os
import zipfile

# Base64 encoded zip data containing all modified/new files
ZIP_DATA = """"""

def apply_patch(target_dir="."):
    zip_bytes = base64.b64decode(ZIP_DATA)
    buf = io.BytesIO(zip_bytes)
    with zipfile.ZipFile(buf, "r") as zf:
        for name in zf.namelist():
            target = os.path.join(target_dir, name)
            os.makedirs(os.path.dirname(target), exist_ok=True)
            with zf.open(name) as src, open(target, "wb") as dst:
                dst.write(src.read())
            print(f"  Extracted: {name}")
    print("Patch applied successfully.")

if __name__ == "__main__":
    import sys
    target = sys.argv[1] if len(sys.argv) > 1 else "."
    print(f"Applying patch to: {os.path.abspath(target)}")
    apply_patch(target)
